import{_ as a,o as r,c as e,a7 as o}from"./chunks/framework.BgApuQ2e.js";const n="/images/4-mind-blowing-things-about-stars/caveman.png",s="/images/4-mind-blowing-things-about-stars/HDF.jpg",p="/images/4-mind-blowing-things-about-stars/690958main_p1237a1.jpg",i="/images/4-mind-blowing-things-about-stars/sad-star.png",l="/images/4-mind-blowing-things-about-stars/VY-Canis-Majoris.png",g="/images/4-mind-blowing-things-about-stars/orion.png",h="/images/4-mind-blowing-things-about-stars/neutron-star.png",m="/images/4-mind-blowing-things-about-stars/pinit_fg_en_rect_gray_20.png",k=JSON.parse('{"title":"4 Mind-Blowing Things About Stars","description":"","frontmatter":{"title":"4 Mind-Blowing Things About Stars","titleZh":"关于恒星的4个惊人事实","date":"2013-11-12T00:00:00.000Z","originalUrl":"https://waitbutwhy.com/2013/11/4-mind-blowing-things-about-stars.html","slug":"4-mind-blowing-things-about-stars"},"headers":[],"relativePath":"posts/4-mind-blowing-things-about-stars.md","filePath":"posts/4-mind-blowing-things-about-stars.md","lastUpdated":1782886257000}'),b={name:"posts/4-mind-blowing-things-about-stars.md"};function c(A,t,_,u,d,w){return r(),e("div",null,[...t[0]||(t[0]=[o('<h1 id="关于恒星的4个惊人事实-·-4-mind-blowing-things-about-stars" tabindex="-1">关于恒星的4个惊人事实 · 4 Mind-Blowing Things About Stars <a class="header-anchor" href="#关于恒星的4个惊人事实-·-4-mind-blowing-things-about-stars" aria-label="Permalink to &quot;关于恒星的4个惊人事实 · 4 Mind-Blowing Things About Stars&quot;">​</a></h1><blockquote><p>原文:<a href="https://waitbutwhy.com/2013/11/4-mind-blowing-things-about-stars.html" target="_blank" rel="noreferrer">https://waitbutwhy.com/2013/11/4-mind-blowing-things-about-stars.html</a> · 2013-11-12</p></blockquote><p>拜托。</p><p>你真的要一整天就坐在那儿只想着自己那点破事,完全不去想想宇宙吗?</p><p>想象一下,你指甲里住着一只细菌,它聪明到对这个世界了解甚多——它对历史掌握得挺不错,能获取大量时事资讯,到了晚上还可以抬起头看看外面的广阔世界。但这只细菌偏偏决定几乎所有时间都无视这一切,反而对你指甲里发生的鸡毛蒜皮痴迷不已。</p><p>我们都会觉得这只细菌挺没出息的,对吧?可你就在这儿,完全无视自己住在这里的事实——</p><p><a href="https://3.bp.blogspot.com/-psLc1FoM2E0/UoK90kgJiDI/AAAAAAAAGRs/t2NVYbMWlIY/s1600/milky+way+(real).png" target="_blank" rel="noreferrer">.png)</a></p><p>——因为你正忙着换三件不同的衬衫,决定不了穿哪件,而且今天下班后大家要一起去喝酒,这事儿很重要。</p><p>正如我之前提过的,我从三岁起就跟天文学认真谈恋爱了,所以 Wait But Why 的使命之一就是提醒你不要老是忽视宇宙。</p><p>今天我们先从一个显而易见的话题开始:恒星。</p><p>人们想到宇宙,想到的就是恒星。恒星构成了宇宙中大部分可见物质,尽管除了太阳之外的所有恒星都离我们远得难以想象,我们晚上肉眼还是能看见几千颗。</p><p>在这篇文章里,我从关于恒星那无穷无尽的迷人事实中筛选出了四个我觉得特别炸脑的——</p><h2 id="_1-可观测宇宙里的恒星数量多到无法想象。" tabindex="-1"><strong>1) 可观测宇宙里的恒星数量多到无法想象。</strong> <a class="header-anchor" href="#_1-可观测宇宙里的恒星数量多到无法想象。" aria-label="Permalink to &quot;**1) 可观测宇宙里的恒星数量多到无法想象。**&quot;">​</a></h2><p>你知道那种情况吧——你晚上在乡下,月亮又没出来,能看到<em>一大堆</em>星星?</p><p>在那种最理想的条件下,你最多看到大约 2500 颗星。这大约是我们自己银河系恒星总数的一亿分之一。</p><p>说到这个,再看一眼上面我们壮丽的银河系。为了帮助你理解它到底有多大得离谱,这里有几个事实:</p><p>– 银河系的直径是 10 万光年。一光年是光在一年里走过的距离。考虑到光在一<em>秒</em>内可以绕地球七圈,一光年就是一个大得让人脑袋短路的距离。我们最快的航天器需要 18000 年才能走完一光年。而银河系,我们说的是 10 万光年。</p><p><a href="https://1.bp.blogspot.com/-B5SVOJ75tBg/UoKRlYZydiI/AAAAAAAAGRM/kGYD4NOyrkk/s1600/caveman.png" target="_blank" rel="noreferrer"><img src="'+n+'" alt=""></a></p><p>—— 这也意味着,如果你用望远镜看银河系另一端的一颗恒星,你实际上看到的是那颗恒星 10 万年前的样子,因为当时从那颗星发出的光刚刚到达我们这里。同样地,如果此时此刻,银河系另一端的某个人正用望远镜看地球,他们会看到一群早期人类和尼安德特人像傻瓜一样跑来跑去,拿棍子互相打。</p><p>—— 你可能会想,当你仔细看上面那张银河系照片时,其中某个小点也许就是我们的太阳。事实上,即使你把上面那张照片放大到地球那么大,你<em>还是</em>得用显微镜才能看到我们那针尖大小的太阳——如果银河系有地球那么大,太阳的直径大约是 1/50 毫米。</p><p>巨大无比。总体来说,银河系包含 1000 亿到 4000 亿颗恒星。</p><p>而这仅仅是一个星系而已。</p><p><a href="https://4.bp.blogspot.com/-uJfHaOUx8Z8/UoJ_6RZe5EI/AAAAAAAAGPs/xGjGMOMTIFk/s1600/HDF.jpg" target="_blank" rel="noreferrer"><img src="'+s+'" alt=""></a>1995 年,科学家们挑选了夜空中一小块异常没有恒星的区域。用肉眼看,甚至用普通望远镜看,这片区域都显得空荡漆黑。而且这块区域小得可怜——它所覆盖的天空大小,相当于把一个网球举到你头顶 100 米高处所遮挡的面积(右边的图显示了这块区域相对于夜空中月亮大小的对比)。</p><p>科学家用哈勃望远镜 (Hubble Telescope) 对这片空旷区域进行了长达 10 天的曝光,想看看那片漆黑深处到底藏着什么。结果他们拿到了这个:</p><p><a href="https://1.bp.blogspot.com/-0UFH_lLMsTc/UoJi1-v8HoI/AAAAAAAAGPE/UXCHRl1_3kk/s1600/690958main_p1237a1.jpg" target="_blank" rel="noreferrer"><img src="'+p+'" alt=""></a></p><p><em>令人瞠目结舌。</em> 说清楚一点,这张照片里没有一个东西是恒星。你看到的每一个东西——哪怕是最微弱的一个小点——都是一整个<em>星系</em>。这张图里有超过 10000 个星系,每一个都包含大约 1000 亿颗恒星。再强调一下,这一切都塞在夜空中针尖大小的一小块方形区域里。</p><p>科学家们利用这张照片的信息推算出,可观测宇宙包含超过 1000 亿个星系,这就把可观测宇宙里<em>恒星</em>的总数推到了 10^22 到 10^24 之间的某个数字,大约 1000 万亿亿颗恒星。</p><p>为了让你有点概念,夏威夷大学的一群人花了不合常理的大量时间,<a href="http://www.hawaii.edu/suremath/jsand.html" target="_blank" rel="noreferrer">估算了一下</a>世界上所有海滩上沙粒的数量——75 亿亿粒,也就是 7.5 x 10^18 粒。</p><p>也就是说,<em><strong>地球上每一片海滩上的每一粒沙,对应着宇宙中大约 10000 颗恒星。</strong></em></p><p>太荒唐了。</p><h2 id="_2-恒星之间彼此并不靠近。" tabindex="-1"><strong>2) 恒星之间彼此并不靠近。</strong> <a class="header-anchor" href="#_2-恒星之间彼此并不靠近。" aria-label="Permalink to &quot;**2) 恒星之间彼此并不靠近。**&quot;">​</a></h2><p><a href="https://4.bp.blogspot.com/-TOvk9Lx7_nU/UoKH_lOJWFI/AAAAAAAAGQc/SOhxlY-sudw/s1600/sad+star.png" target="_blank" rel="noreferrer"><img src="'+i+'" alt=""></a>双星系统另说,大部分恒星就孤零零地待在那儿,朝任何方向看都是好远好远的距离里没人陪,无聊透顶。</p><p>我们的太阳也不例外——离我们最近的恒星是比邻星 (Proxima Centauri),距离 4.24 光年,用我们最快的宇宙飞船去也得飞 7 万年。</p><p>所以如果把太阳缩成一个直径 4 厘米的乒乓球放在纽约,那么最近的那颗恒星就是另一个乒乓球,放在 1153 公里(743 英里)之外的亚特兰大。</p><h2 id="_3-有些恒星大得离谱。" tabindex="-1"><strong>3) 有些恒星大得离谱。</strong> <a class="header-anchor" href="#_3-有些恒星大得离谱。" aria-label="Permalink to &quot;**3) 有些恒星大得离谱。**&quot;">​</a></h2><p>最大的恒星叫红特超巨星 (red hypergiant)。有一颗大得荒唐的叫大犬座 VY (VY Canis Majoris)。把 1420 个太阳摞起来,直径才顶得上一颗大犬座 VY。看看它跟太阳站在一起的样子:</p><p><a href="https://2.bp.blogspot.com/-AUzgrtrRzK4/UoKY1loBP9I/AAAAAAAAGRc/iDjUDtqviSI/s1600/VY-Canis-Majoris.png" target="_blank" rel="noreferrer"><img src="'+l+'" alt=""></a></p><p>或者,把太阳换回那个乒乓球大小,大犬座 VY 就相当于一栋 16 层楼高的建筑。一架飞机绕它飞一圈得花大约 1100 年;要是把大犬座 VY 放到太阳系中心太阳现在的位置上,它会一口把土星轨道以内的所有东西全吞掉。</p><p>另一颗几乎跟大犬座 VY 一样大的红特超巨星是参宿四 (Betelgeuse)。任何一个有星星的夜晚你都能看到参宿四——它是猎户座左上肩那颗——</p><p><a href="https://2.bp.blogspot.com/-ghQDRSpVHJ8/UoKBJdtjzPI/AAAAAAAAGP4/C0JxgkVJoL4/s1600/orion.png" target="_blank" rel="noreferrer"><img src="'+g+'" alt=""></a></p><h2 id="_4-有些恒星小得可怕-密度大得离谱。" tabindex="-1"><strong>4) 有些恒星小得可怕,密度大得离谱。</strong> <a class="header-anchor" href="#_4-有些恒星小得可怕-密度大得离谱。" aria-label="Permalink to &quot;**4) 有些恒星小得可怕,密度大得离谱。**&quot;">​</a></h2><p>当一颗大恒星以超新星爆发的方式死亡时,可能发生引力坍缩,结果就是一颗中子星。</p><p>普通物质由原子构成,而原子几乎全是空的。给原子提供质量的,只是正中间那个小小的原子核。为了让你有个直观感受,想象一个原子是一个直径 1 公里的大球——这球大到你可以在里面摞两栋帝国大厦都不会顶到天花板。如果这个球是一个原子,那原子核就相当于飘在正中间的一颗豌豆,而整个原子的质量就等于那颗豌豆的质量。</p><p>引力坍缩成中子星的过程里,原子被挤得实在太狠,每个原子里的空间全塌了,每个原子中间的那颗豌豆突然全堆到了一起。现在再想象那个直径 1 公里的球,只不过它<em>塞满了豌豆</em>。原来那 1 公里的空间只有 1 颗豌豆的质量,现在有大约 1,000,000,000,000,000 颗豌豆的质量。</p><p>这就是中子星形成时发生的事——里面没有一丁点空间,只有构成原子核的那些中子紧紧挤在一起——它的密度是普通恒星的一<em>千万亿</em>倍。</p><p>结果就是一颗直径仅约 24 公里的小星星,质量却相当于三个太阳,或者说<em>一百万个地球</em>。下面是一颗中子星的大小——想象一下把 1,000,000 个地球塞进去:</p><p><a href="https://2.bp.blogspot.com/-YZ-c9hKCChw/UoKFlufIEII/AAAAAAAAGQQ/pGzKcrla41c/s1600/neutron+star.png" target="_blank" rel="noreferrer"><img src="'+h+'" alt=""></a></p><p>一些让人震惊的中子星事实:</p><p>– 一茶匙中子星物质的质量,等于<em>900 座吉萨大金字塔</em>。 <em>–</em> 中子星的密度,相当于把一架波音 747 飞机压缩成一粒小沙子。</p><p>– 有些中子星的自转速度快到<em>每秒 642 圈</em>。这意味着中子星「赤道」上一个点每秒移动的距离,比地球的周长还要长。</p><p>– 中子星非常<em>热</em>。中子星的内部温度在 10^11 到 10^12 开尔文之间——比太阳核心热 1000 多倍。</p><p>挺让人招架不住的。</p><p>好了,干得不错。现在回到指甲盖上来。</p><p><strong>相关 Wait But Why 文章</strong></p><p><a href="https://waitbutwhy.com/2015/08/how-and-why-spacex-will-colonize-mars.html" target="_blank" rel="noreferrer">SpaceX 将如何(以及为什么)殖民火星</a></p><p><a href="https://waitbutwhy.com/2014/05/fermi-paradox.html" target="_blank" rel="noreferrer">费米悖论 (The Fermi Paradox)</a></p><h2 id="ai-革命-通往超级智能之路" tabindex="-1"><a href="https://waitbutwhy.com/2015/01/artificial-intelligence-revolution-1.html" target="_blank" rel="noreferrer">AI 革命:通往超级智能之路</a> <a class="header-anchor" href="#ai-革命-通往超级智能之路" aria-label="Permalink to &quot;[AI 革命:通往超级智能之路](https://waitbutwhy.com/2015/01/artificial-intelligence-revolution-1.html)&quot;">​</a></h2><p>如果你喜欢 Wait But Why,请订阅我们的**<a href="https://newsletter.waitbutwhy.com/join" target="_blank" rel="noreferrer">邮件列表</a>**,新文章发布时我们会发给你。</p><p>想支持 Wait But Why,请访问我们的 <strong><a href="https://patreon.com/waitbutwhy" target="_blank" rel="noreferrer">Patreon 页面</a></strong>。</p><p><a href="https://twitter.com/share" target="_blank" rel="noreferrer">Tweet</a></p><p><a href="//www.pinterest.com/pin/create/button/?url=https://waitbutwhy.com/2013/11/4-mind-blowing-things-about-stars.html&amp;description=4%20Mind-Blowing%20Things%20About%20Stars" target="_blank" rel="noreferrer"><img src="'+m+'" alt=""></a></p>',61)])])}const y=a(b,[["render",c]]);export{k as __pageData,y as default};
